class Command(BaseCommand):
    help = 'Popula o banco com as missões atualizadas do Detetive Linux.'
    def handle(self, *args, **options):
        created=updated=0
        for data in MISSIONS:
            obj, was_created = Mission.objects.update_or_create(phase=data['phase'], order=data['order'], defaults=data)
            created += int(was_created); updated += int(not was_created)
        self.stdout.write(self.style.SUCCESS(f'Missões carregadas. Criadas: {created}. Atualizadas: {updated}. Total: {Mission.objects.count()}'))
